"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const levels=[["Low","Can wait until the next planning pass"],["Medium","Keep it in this week’s review"],["High","Needs attention before handoff"]];
export default function PriorityPulseField(){const [level,setLevel]=useState(1);const reduced=useReducedMotion();return <fieldset className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><legend className="text-lg font-black text-[#111]">Task priority</legend><p className="mt-1 text-sm text-[#4a4a4f]">Choose a review urgency.</p><div className="mt-4 grid grid-cols-3 gap-2">{levels.map(([name],index)=><label key={name} className="cursor-pointer"><input className="sr-only" type="radio" name="priority" checked={level===index} onChange={()=>setLevel(index)}/><motion.span whileTap={reduced?undefined:{scale:.97}} className={level===index?"flex min-h-11 items-center justify-center rounded-xl border-2 border-[#111] bg-[#fff0ec] text-sm font-black":"flex min-h-11 items-center justify-center rounded-xl border border-[#ececee] text-sm font-bold"}>{name}</motion.span></label>)}</div><p aria-live="polite" className="mt-4 text-sm text-[#4a4a4f]"><b className="text-[#111]">{levels[level][0]}:</b> {levels[level][1]}</p></fieldset>}
